// Refs: 'PL Fetch Invoices'
const invoices = $input.first().json.items;
const today = new Date().toISOString().split('T')[0];
const THRESHOLD_DAYS = 7;

const overdue = [];

for (const inv of invoices) {
  if (inv.draft || inv.paid) continue;
  if (inv.deadline >= today) continue;

  const deadlineDate = new Date(inv.deadline);
  const todayDate = new Date(today);
  const daysOverdue = Math.floor((todayDate - deadlineDate) / (1000 * 60 * 60 * 24));

  if (daysOverdue >= THRESHOLD_DAYS) {
    overdue.push({
      id: inv.id,
      invoice_number: inv.invoice_number,
      label: inv.label,
      currency_amount: inv.currency_amount,
      currency: inv.currency,
      deadline: inv.deadline,
      days_overdue: daysOverdue,
      customer_id: inv.customer.id,
      public_file_url: inv.public_file_url
    });
  }
}

return [{
  json: {
    overdue_count: overdue.length,
    overdue,
    has_overdue: overdue.length > 0
  }
}];

// Refs: 'Code Filter Overdue'
const data = $input.first().json;
const lines = ['🚨 Overdue Invoice Reminder', ''];

lines.push(`${data.overdue_count} invoice(s) require attention:`);
lines.push('');

for (const inv of data.overdue) {
  lines.push(`• ${inv.invoice_number} | ${inv.currency_amount} ${inv.currency}`);
  lines.push(`  Due: ${inv.deadline} (${inv.days_overdue} days overdue)`);
  lines.push(`  ${inv.public_file_url}`);
  lines.push('');
}

return [{
  json: {
    message: lines.join('\n'),
    overdue_count: data.overdue_count
  }
}];
